const fetch = require('node-fetch');
const baseUrl = process.env.ML_API_URL || 'http://ml-api:8503';
const token = process.env.ML_API_TOKEN || '';

const q = (typeof $query !== 'undefined' && $query) ? String($query).trim() : '';
if (!q) {
    return JSON.stringify({ error: 'Informe query com nome, fornecedor ou id_insumo.' });
}

let limit = 10;
if (typeof $limit !== 'undefined' && $limit !== null && $limit !== '') {
    const parsed = parseInt($limit, 10);
    if (!isNaN(parsed)) limit = Math.min(20, Math.max(1, parsed));
}

const headers = {};
if (token) headers['Authorization'] = `Bearer ${token}`;

const url = `${baseUrl}/insumos/search?q=${encodeURIComponent(q)}&limit=${limit}`;

try {
    const response = await fetch(url, { method: 'GET', headers });
    const text = await response.text();
    if (!response.ok) {
        return JSON.stringify({ error: text, status: response.status });
    }
    return text;
} catch (error) {
    console.error(error);
    return JSON.stringify({ error: String(error) });
}
